(window.webpackJsonp=window.webpackJsonp||[]).push([[280],{907:function(r,n){r.exports="\x3c!-- \r\ntitle: A3-Numpy入门\r\nsort: \r\n--\x3e \r\n#  Numpy入门\r\n\r\n## 创建数据\r\n\r\n```python\r\nimport numpy as np\r\n# 创建np数组\r\nnp.array([1,2,3])\r\n# 创建十个空数组\r\nnp.zeros(10)\r\n#\t使用4填充一个10*10数组\r\nnp.full((10,10),2)\r\n# 创建1-100的数组\r\narr = np.arange(100)\r\n# 改变数组形状\r\narr = arr.reshape(10,10)\r\n```\r\n\r\n### ndarray的参数\r\n\r\n```python\r\narr.ndim\t# 阶数\r\narr.shape\t# 形状\r\narr.dtype\t# 元素类型\r\narr.itemsize\t# 字节数\r\narr.size\t\t# 数据大小\r\n```\r\n\r\n## 提取数据\r\n\r\n```python\r\narr[0][1]\t# 提取二阶数组\r\narr[5,3:-1:2]\t#第六行 第三个到最后 步长为2\r\narr[[0,6],::2]\t# 第一行 与 第七行 步长2\r\narr[arr > 50]\t# 提取大于50的数据\r\n```\r\n\r\n## 操作数据\r\n\r\n```python\r\nnp.max(arr,axis=1)\t# y轴提取最大值\r\nnp.sum(arr,axis=0)\t# 按列相加\r\nnp.sin(arr[0])\t\t# 求sin\r\narr[:,1]*arr[:,3]\t# 第一列乘以第三列\r\nnumpy.apply_along_axis(func, axis, arr, *args, **kwargs)\r\nnp.apply_along_axis(lambda x:print(x[1]+x[3]*x[5]), arr = arr ,axis = 1)\t# 对arr里的每一个元素进行函数变换\r\n# 向下拼接数组\r\nnp.vstack([arr,arr2])\r\n# 向右拼接数组\r\nnp.hstack([arr,arr3])\r\n\r\n```\r\n\r\n## 打开文件\r\n\r\n```python\r\n# 提取csv\r\nnp.genfromtxt('csv.csv', delimiter = ',', dtype = 'int16')\t\r\n# fmt指定存储类型\r\nnp.savetxt('2.csv', arr, fmt='%d', delimiter = ',')\r\n```\r\n\r\n"}}]);